3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Handshake pipeline. Is used to ease the timing of a streaming data interface by inserting
10	-- register stages on the data and/or control signals.
11	--
12	-- There are many modes available, with different characteristics, that are enabled
13	-- with different combinations of ``full_throughput``, ``pipeline_control_signals``
14	-- and ``pipeline_data_signals``.
15	-- See the descriptions within the code for more details about throughput and fanout.
16	-- -------------------------------------------------------------------------------------------------
17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	
21	
22	entity handshake_pipeline is
23	  generic (
24	    data_width : natural;
25	    -- Setting to false can save logic footprint, at the cost of lower throughput
26	    full_throughput : boolean := true;
27	    -- Ensures that there is no combinatorial path between valid and ready on input and output.
28	    -- Will result in higher logic footprint.
29	    pipeline_control_signals : boolean := true;
30	    -- Ensures that there is no combinatorial path from data, strobe and last on input to output.
31	    -- Will result in higher logic footprint.
32	    pipeline_data_signals : boolean := true;
33	    -- In the typical use case where we want a "byte strobe", this would be eight.
34	    -- In other cases, for example when the data is packed, we might use a higher value.
35	    -- Must assign a valid value if input/output strobe is to be used.
36	    strobe_unit_width : positive := 8
37	  );
38	  port (
39	    clk : in std_ulogic;
40	    --# {{}}
41	    input_ready : out std_ulogic := '0';
42	    input_valid : in std_ulogic;
43	    -- Optional to connect.
44	    input_last : in std_ulogic := '-';
45	    input_data : in std_ulogic_vector(data_width - 1 downto 0) := (others => '-');
46	    -- Optional to connect. Must set valid 'strobe_unit_width' generic value in order to use this.
47	    input_strobe : in std_ulogic_vector(data_width / strobe_unit_width - 1 downto 0) :=
48	      (others => '-');
49	    --# {{}}
50	    output_ready : in std_ulogic;
51	    output_valid : out std_ulogic := '0';
52	    output_last : out std_ulogic := '0';
53	    output_data : out std_ulogic_vector(data_width - 1 downto 0) := (others => '0');
54	    output_strobe : out std_ulogic_vector(data_width / strobe_unit_width - 1 downto 0) :=
55	      (others => '0')
56	  );
57	end entity;
58	
59	architecture a of handshake_pipeline is
60	
61	begin
62	
63	  ------------------------------------------------------------------------------
64	  choose_mode : if full_throughput and pipeline_data_signals and pipeline_control_signals generate
65	
66	    -- This mode is a full skid-aside buffer, aka skid buffer.
67	    --
68	    -- It makes sure that all output signals (data as well as control signals) are driven by
69	    -- a register.  It does so while sustaining full throughput. It has the best timing
70	    -- characteristics but also the largest logic footprint.
71	
72	    signal input_ready_int : std_ulogic := '1';
73	
74	    type state_t is (wait_for_input_valid, full_handshake_throughput, wait_for_output_ready);
75	    signal state : state_t := wait_for_input_valid;
76	
77	    signal input_last_skid : std_ulogic := '0';
78	    signal input_data_skid : std_ulogic_vector(input_data'range) := (others => '0');
79	    signal input_strobe_skid : std_ulogic_vector(input_strobe'range) := (others => '0');
80	
81	  begin
82	
83	    input_ready <= input_ready_int;
84	
85	
86	    ------------------------------------------------------------------------------
87	    main : process
88	    begin
89	      wait until rising_edge(clk);
90	
91	      case state is
92	        when wait_for_input_valid =>
93	          if input_valid then
94	            -- input_ready is '1', so if we get here an input transaction has occurred
95	            output_valid <= '1';
96	            output_last <= input_last;
97	            output_data <= input_data;
98	            output_strobe <= input_strobe;
99	
100	            state <= full_handshake_throughput;
101	          end if;
102	
103	        when full_handshake_throughput =>
104	          -- input_ready and output_valid are always '1' in this state
105	
106	          if input_valid and output_ready then
107	            -- Input and output transactions have occurred. Update data register.
108	            output_last <= input_last;
109	            output_data <= input_data;
110	            output_strobe <= input_strobe;
111	
112	          elsif output_ready then
113	            -- Output transaction has occurred, but no input transaction
114	            output_valid <= '0';
115	
116	            state <= wait_for_input_valid;
117	
118	          elsif input_valid then
119	            -- Input transaction has occurred, but no output transaction
120	            -- Values from input transaction will be saved in the skid-aside buffer while we wait
121	            -- for output_ready.
122	            input_ready_int <= '0';
123	
124	            state <= wait_for_output_ready;
125	          end if;
126	
127	        when wait_for_output_ready =>
128	          if output_ready then
129	            -- output_valid is '1', so if we get here an output transaction has occurred
130	            input_ready_int <= '1';
131	
132	            output_last <= input_last_skid;
133	            output_data <= input_data_skid;
134	            output_strobe <= input_strobe_skid;
135	
136	            state <= full_handshake_throughput;
137	          end if;
138	      end case;
139	
140	      if input_ready and input_valid then
141	        input_last_skid <= input_last;
142	        input_data_skid <= input_data;
143	        input_strobe_skid <= input_strobe;
144	      end if;
145	    end process;
146	
147	
148	  ------------------------------------------------------------------------------
149	  elsif full_throughput and pipeline_data_signals and (not pipeline_control_signals) generate
150	
151	    -- In this mode, the data and control signals are driven by registers, except for input_ready
152	    -- which will have an increased critical path. It still maintains full throughput,
153	    -- and has a much smaller footprint than the full skid-aside buffer.
154	    --
155	    -- It is suitable in situations where there is a complex net driving the data, which needs to
156	    -- be pipelined in order to achieve timing closure, but the timing of the control signals is
157	    -- not critical.
158	
159	    input_ready <= output_ready or not output_valid;
160	
161	
162	    ------------------------------------------------------------------------------
163	    main : process
164	    begin
165	      wait until rising_edge(clk);
166	
167	      if input_ready then
168	        output_valid <= input_valid;
169	        output_last <= input_last;
170	        output_data <= input_data;
171	        output_strobe <= input_strobe;
172	      end if;
173	    end process;
174	
175	
176	  ------------------------------------------------------------------------------
177	  elsif (not full_throughput) and pipeline_data_signals and pipeline_control_signals generate
178	
179	    -- All signals are driven by registers, which results in the best timing but also the lowest
180	    -- throughput. This mode will be able to maintain a one third throughput.
181	
182	    ------------------------------------------------------------------------------
183	    main : process
184	    begin
185	      wait until rising_edge(clk);
186	
187	      input_ready <= output_ready and output_valid;
188	      -- Since there is a one cycle latency on output_valid, and a one cycle latency on input_ready,
189	      -- we have to stall for two cycles after a transaction, to allow the "input" master to update
190	      -- data and valid.
191	      output_valid <= input_valid and not (output_valid and output_ready) and not input_ready;
192	      output_last <= input_last;
193	      output_data <= input_data;
194	      output_strobe <= input_strobe;
195	    end process;
196	
197	
198	  ------------------------------------------------------------------------------
199	  elsif (not full_throughput) and pipeline_data_signals and (not pipeline_control_signals) generate
200	
201	    -- All signals are driven by registers, except input_ready which will have an increased
202	    -- critical path. This mode will be able to maintain a one half throughput.
203	    --
204	    -- Compared to the "full_throughput and pipeline_data_signals and not pipeline_control_signals"
205	    -- above, this one has a lower load on the input_ready.
206	    -- This results in somewhat better timing on the input_ready signal, at the cost of
207	    -- lower throughput.
208	
209	  begin
210	
211	    input_ready <= output_ready and output_valid;
212	
213	
214	    ------------------------------------------------------------------------------
215	    main : process
216	    begin
217	      wait until rising_edge(clk);
218	
219	      output_valid <= input_valid and not (output_valid and output_ready);
220	      output_last <= input_last;
221	      output_data <= input_data;
222	      output_strobe <= input_strobe;
223	    end process;
224	
225	
226	  ------------------------------------------------------------------------------
227	  elsif (not pipeline_data_signals) and pipeline_control_signals generate
228	
229	    -- Control signals are pipelined while data, last and strobe signals
230	    -- are driven directly from input to output.
231	    -- This mode will be able to maintain a third throughput.
232	
233	    type state_t is (wait_for_input_valid, wait_for_output_ready);
234	    signal state : state_t := wait_for_input_valid;
235	
236	  begin
237	
238	    assert not full_throughput
239	      report "Does not support full throughput when only pipelining control signals"
240	      severity failure;
241	
242	
243	    ------------------------------------------------------------------------------
244	    main : process
245	    begin
246	      wait until rising_edge(clk);
247	
248	      case state is
249	        when wait_for_input_valid =>
250	          input_ready <= '0';
251	
252	          -- Proceed to output the input data, but only if we are not waiting for a pop
253	          -- of the previous input
254	          if input_valid and not input_ready then
255	            -- Input is valid, so signal that it can be used for output.
256	            -- We don't pop it from the input yet, because we don't want an extra register stage
257	            -- for data in this mode.
258	            output_valid <= '1';
259	            state <= wait_for_output_ready;
260	          end if;
261	
262	        when wait_for_output_ready =>
263	          assert output_valid report "Should not be able to get here without valid output";
264	          assert input_valid report "Should not be able to get here without valid input";
265	
266	          -- Wait for output ready and then pop the input
267	          if output_ready then
268	            -- Pop the input word next cycle
269	            input_ready <= '1';
270	            output_valid <= '0';
271	            state <= wait_for_input_valid;
272	          end if;
273	
274	      end case;
275	    end process;
276	
277	    output_data <= input_data;
278	    output_strobe <= input_strobe;
279	    output_last <= input_last;
280	
281	  elsif (not pipeline_data_signals) and (not pipeline_control_signals) generate
282	
283	    -- This mode will simply create a passthrough.
284	    -- This may be handy if you want to see how removing a pipeline stage affects timing.
285	
286	    input_ready <= output_ready;
287	    output_valid <= input_valid;
288	    output_data <= input_data;
289	    output_strobe <= input_strobe;
290	    output_last <= input_last;
291	
292	  end generate;
293	
294	end architecture;
295

