1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Multiplex between many AXI-Stream-like inputs towards one output bus.
10	-- Will lock onto one ``input`` and let its data through until a packet has passed, as indicated
11	-- by the ``last`` signal.
12	--
13	-- The implementation is simple, which comes with a few limitations:
14	--
15	-- .. warning::
16	--
17	--   If there are holes in an ``input`` packet stream after ``valid`` has been asserted, this
18	--   multiplexer will be unnecessarily stalled even if another ``input`` has data available.
19	--   It is up to the user to make sure that this does not occur, using e.g. a :ref:`fifo.fifo`
20	--   in packet mode, or calculate that the system throughput is still sufficient.
21	--
22	--   The arbitration is done in the simplest most resource-efficient manner possible, which
23	--   means that one ``input`` can block others if it continuously sends data.
24	-- -------------------------------------------------------------------------------------------------
25	
26	library ieee;
27	use ieee.std_logic_1164.all;
28	use ieee.numeric_std.all;
29	
30	use work.types_pkg.all;
31	
32	
33	entity handshake_mux is
34	  generic (
35	    num_inputs : positive;
36	    data_width : positive
37	  );
38	  port (
39	    clk : in std_ulogic;
40	    --# {{}}
41	    input_ready : out std_ulogic_vector(0 to num_inputs - 1) := (others => '0');
42	    input_valid : in std_ulogic_vector(0 to num_inputs - 1);
43	    input_last : in std_ulogic_vector(0 to num_inputs - 1) := (others => '1');
44	    input_data : in slv_vec_t(0 to num_inputs - 1)(data_width - 1 downto 0);
45	    input_strobe : in slv_vec_t(0 to num_inputs - 1)(data_width / 8 - 1 downto 0) :=
46	      (others => (others => '1'));
47	    --# {{}}
48	    result_ready : in std_ulogic;
49	    result_valid : out std_ulogic := '0';
50	    result_last : out std_ulogic := '1';
51	    result_data : out std_ulogic_vector(data_width - 1 downto 0) := (others => '0');
52	    result_strobe : out std_ulogic_vector(data_width / 8 - 1 downto 0) := (others => '0');
53	    -- The input port index where the packet originated
54	    result_id : out natural range 0 to num_inputs - 1 := 0
55	  );
56	end entity;
57	
58	architecture a of handshake_mux is
59	
60	  type state_t is (wait_for_valid_input, wait_for_data_packet_done);
61	  signal state : state_t := wait_for_valid_input;
62	
63	  signal input_select : natural range input_valid'range := 0;
64	
65	begin
66	
67	  ------------------------------------------------------------------------------
68	  main : process
69	  begin
70	    wait until rising_edge(clk);
71	
72	    case state is
73	      when wait_for_valid_input =>
74	        for input_idx in input_valid'range loop
75	          if input_valid(input_idx) then
76	            input_select <= input_idx;
77	
78	            state <= wait_for_data_packet_done;
79	          end if;
80	        end loop;
81	
82	      when wait_for_data_packet_done =>
83	        if result_ready and result_valid and result_last then
84	          state <= wait_for_valid_input;
85	        end if;
86	
87	    end case;
88	  end process;
89	
90	
91	  ------------------------------------------------------------------------------
92	  assign : process(all)
93	  begin
94	    input_ready <= (others => '0');
95	
96	    result_valid <= '0';
97	
98	    -- Can alway be assigned, valid is only ever '1' if we have locked on to a valid input
99	    result_last <= input_last(input_select);
100	    result_data <= input_data(input_select);
101	    result_strobe <= input_strobe(input_select);
102	    result_id <= input_select;
103	
104	    if state = wait_for_data_packet_done then
105	      input_ready(input_select) <= result_ready;
106	
107	      result_valid <= input_valid(input_select);
108	    end if;
109	  end process;
110	
111	end architecture;
112

