    def _get_event_aggregator_build_projects(
        self, part: str, projects: list[TsfpgaExampleVivadoNetlistProject]
    ) -> None:
        def add(lut: int, ff: int, logic: int, event_count: int = 1, tick_count: int = 1) -> None:
